/*
 * fabsf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly fabsf  (test_fabsf_opt.elf)
 *   2. Linked with toolchain's default fabsf        (test_fabsf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += fabsf(vx);
#else
    float r = fabsf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

#ifndef EN_PERF
static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#else
static void emit_u(uint32_t bits)
{
    volatile float vx = u2f(bits);
    g_acc += fabsf(vx);
}
#endif

/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* smallest positive normal: 0x00800000 */
    emit(-FLT_MIN);               /* smallest negative normal */
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX */
    emit_u(0xff7fffffu);          /* -FLT_MAX */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    emit(1.0f);           /* 1.0: 0x3f800000 */
    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* several ULPs below 1.0 */
    emit_u(0x3f800010u);  /* several ULPs above 1.0 */
    emit(-1.0f);          /* -1.0: 0xbf800000 */
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (10) --- */
    emit_u(0x3f000000u);  /* 0.5 */
    emit_u(0xbf000000u);  /* -0.5 */
    emit_u(0x3effffffu);  /* one ULP below 0.5 */
    emit_u(0x3f000001u);  /* one ULP above 0.5 */
    emit_u(0x40000000u);  /* 2.0 */
    emit_u(0xc0000000u);  /* -2.0 */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
    emit_u(0x40000001u);  /* one ULP above 2.0 */
    emit_u(0x3e800000u);  /* 0.25 */
    emit_u(0xbe800000u);  /* -0.25 */

    /* --- Section 6: Power-of-2 values positive and negative (14) --- */
    emit_u(0x3e000000u);  /* 0.125 = 2^-3 */
    emit_u(0xbe000000u);  /* -0.125 */
    emit_u(0x40800000u);  /* 4.0 = 2^2 */
    emit_u(0xc0800000u);  /* -4.0 */
    emit_u(0x41000000u);  /* 8.0 = 2^3 */
    emit_u(0xc1000000u);  /* -8.0 */
    emit_u(0x41800000u);  /* 16.0 = 2^4 */
    emit_u(0xc1800000u);  /* -16.0 */
    emit_u(0x42000000u);  /* 32.0 = 2^5 */
    emit_u(0xc2000000u);  /* -32.0 */
    emit_u(0x42800000u);  /* 64.0 = 2^6 */
    emit_u(0xc2800000u);  /* -64.0 */
    emit_u(0x43000000u);  /* 128.0 = 2^7 */
    emit_u(0xc3000000u);  /* -128.0 */

    /* --- Section 7: Fractional values both signs (14) --- */
    emit(0.1f);
    emit(-0.1f);
    emit(0.375f);
    emit(-0.375f);
    emit(0.625f);
    emit(-0.625f);
    emit(0.75f);
    emit(-0.75f);
    emit(0.875f);
    emit(-0.875f);
    emit(0.999f);
    emit(-0.999f);
    emit(1.5f);
    emit(-1.5f);

    /* --- Section 8: Large values (10) --- */
    emit(1.0e6f);
    emit(-1.0e6f);
    emit(1.0e10f);
    emit(-1.0e10f);
    emit(1.0e20f);
    emit(-1.0e20f);
    emit(1.0e30f);
    emit(-1.0e30f);
    emit_u(0x7f000000u);  /* 2^126: large normal, half of FLT_MAX exponent range */
    emit_u(0xff000000u);  /* -2^126 */

    /* --- Section 9: Very small normals (10) --- */
    emit(1.0e-10f);
    emit(-1.0e-10f);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-30f);
    emit(-1.0e-30f);
    emit(1.0e-38f);
    emit(-1.0e-38f);
    emit_u(0x00800002u);  /* two ULPs above FLT_MIN */
    emit_u(0x80800002u);  /* two ULPs above -FLT_MIN (toward zero) */

    /* --- Section 10: Arbitrary sign-bit stress patterns (15) --- */
    emit_u(0x40490fdbu);  /* pi: 0x40490fdb */
    emit_u(0xc0490fdbu);  /* -pi */
    emit_u(0x3fc90fdbu);  /* pi/2: 0x3fc90fdb */
    emit_u(0xbfc90fdbu);  /* -pi/2 */
    emit_u(0x3f317218u);  /* ln2: 0x3f317218 */
    emit_u(0xbf317218u);  /* -ln2 */
    emit_u(0x40c90fdbu);  /* 2*pi: 0x40c90fdb */
    emit_u(0xc0c90fdbu);  /* -2*pi */
    emit_u(0x42b17218u);  /* exp overflow threshold ~88.7: 0x42b17218 */
    emit_u(0xc2b17218u);  /* negative exp overflow threshold */
    emit_u(0x3f490fdbu);  /* pi/4: 0x3f490fdb */
    emit_u(0xbf490fdbu);  /* -pi/4 */
    emit_u(0x3ec90fdbu);  /* pi/8: 0x3ec90fdb */
    emit_u(0xbec90fdbu);  /* -pi/8 */
    emit_u(0x55555555u);  /* arbitrary alternating bit pattern with positive sign */
}

/* ------------------------------------------------------------------ */

/* 7. Sweep [-4*pi, 4*pi] in 200 steps */
#ifndef EN_PERF
static void test_sweep(void)
{
    float hi = 4.0f * 3.14159265358979323846f;
    int nsteps = 200;
    float step = (2.0f * hi) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [-1, 1] every 4194304 ULP (~500 cases) */
static void test_exhaustive_small(void)
{
    uint32_t start = 0xbf800000u; /* -1.0 */
    uint32_t end = 0x3f800000u;   /* 1.0 */

    for (uint32_t b = start; b <= end; b += 2097152)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
